    27|
    28|type NormalizedMessage = {
    29|  role: string;
    30|  content: string;
    31|};
    32|
    33|/**
    34| * Normalize backend onboarding messages into a strict `{role, content}` list.
    35| *
    36| * The server stores messages as untyped JSON; this protects the UI from partial
    37| * or malformed entries.
    38| */
    39|const normalizeMessages = (
    40|  value?: BoardOnboardingReadMessages,
    41|): NormalizedMessage[] | null => {
    42|  if (!value) return null;
    43|  if (!Array.isArray(value)) return null;
    44|  const items: NormalizedMessage[] = [];
    45|  for (const entry of value) {
    46|    if (!entry || typeof entry !== "object") continue;
    47|    const raw = entry as Record<string, unknown>;
    48|    const role = typeof raw.role === "string" ? raw.role : null;
    49|    const content = typeof raw.content === "string" ? raw.content : null;
    50|    if (!role || !content) continue;
    51|    items.push({ role, content });
    52|  }
    53|  return items.length ? items : null;
    54|};
    55|
    56|type QuestionOption = { id: string; label: string };
    57|
    58|type Question = {
    59|  question: string;
    60|  options: QuestionOption[];
    61|};
    62|
    63|const FREE_TEXT_OPTION_RE =
    64|  /(i'?ll type|i will type|type it|type my|other|custom|free\\s*text)/i;
    65|
    66|const isFreeTextOption = (label: string) => FREE_TEXT_OPTION_RE.test(label);
    67|
    68|/**
    69| * Best-effort parser for assistant-produced question payloads.
    70| *
    71| * During onboarding, the assistant can respond with either:
    72| * - raw JSON (ideal)
    73| * - a fenced ```json block
    74| * - slightly-structured objects
    75| *
    76| * This function validates shape and normalizes option ids/labels.
    77| */
    78|const normalizeQuestion = (value: unknown): Question | null => {
    79|  if (!value || typeof value !== "object") return null;
    80|  const data = value as { question?: unknown; options?: unknown };
    81|  if (typeof data.question !== "string" || !Array.isArray(data.options))
    82|    return null;
    83|  const options: QuestionOption[] = data.options
    84|    .map((option, index) => {
    85|      if (typeof option === "string") {
    86|        return { id: String(index + 1), label: option };
    87|      }
    88|      if (option && typeof option === "object") {
    89|        const raw = option as { id?: unknown; label?: unknown };
    90|        const label =
    91|          typeof raw.label === "string"
    92|            ? raw.label
    93|            : typeof raw.id === "string"
    94|              ? raw.id
    95|              : null;
    96|        if (!label) return null;
    97|        return {
    98|          id: typeof raw.id === "string" ? raw.id : String(index + 1),
    99|          label,
   100|        };
   101|      }
   102|      return null;
   103|    })
   104|    .filter((option): option is QuestionOption => Boolean(option));
   105|  if (!options.length) return null;
   106|  return { question: data.question, options };
   107|};
   108|
   109|/**
   110| * Extract the most recent assistant question from the transcript.
   111| *
   112| * We intentionally only inspect the last assistant message: the user may have
   113| * typed arbitrary text between questions.
   114| */
   115|const parseQuestion = (messages?: NormalizedMessage[] | null) => {
   116|  if (!messages?.length) return null;
   117|  const lastAssistant = [...messages]
   118|    .reverse()
   119|    .find((msg) => msg.role === "assistant");
   120|  if (!lastAssistant?.content) return null;
   121|  try {
   122|    return normalizeQuestion(JSON.parse(lastAssistant.content));
   123|  } catch {
   124|    const match = lastAssistant.content.match(/```(?:json)?\s*([\s\S]*?)```/);
   125|    if (match) {
   126|      try {
   127|        return normalizeQuestion(JSON.parse(match[1]));
   128|      } catch {
   129|        return null;
   130|      }
   131|    }
   132|  }
   133|  return null;
   134|};
   135|
   136|export function BoardOnboardingChat({
   137|  boardId,
   138|  onConfirmed,
   139|}: {
   140|  boardId: string;
   141|  onConfirmed: (board: BoardRead) => void;
