{"content": "     1|"use client";
     2|
     3|import { memo, useCallback, useEffect, useMemo, useRef, useState } from "react";
     4|
     5|import { Button } from "@/components/ui/button";
     6|import { Textarea } from "@/components/ui/textarea";
     7|
     8|const MENTION_MAX_OPTIONS = 8;
     9|const MENTION_PATTERN = /(?:^|\s)@([A-Za-z0-9_-]{0,31})$/;
    10|
    11|type MentionTarget = {
    12|  start: number;
    13|  end: number;
    14|  query: string;
    15|};
    16|
    17|type BoardChatComposerProps = {
    18|  placeholder?: string;
    19|  isSending?: boolean;
    20|  disabled?: boolean;
    21|  mentionSuggestions?: string[];
    22|  onSend: (content: string) => Promise<boolean>;
    23|};
    24|
    25|const normalizeMentionHandle = (raw: string): string | null => {
    26|  const trimmed = raw.trim().replace(/^@+/, "");
    27|  if (!trimmed) return null;
    28|  const token = trimmed.split(/\s+/)[0]?.replace(/[^A-Za-z0-9_-]/g, "") ?? "";
    29|  if (!token) return null;
    30|  if (!/^[A-Za-z]/.test(token)) return null;
    31|  return token.slice(0, 32).toLowerCase();
    32|};
    33|
    34|const findMentionTarget = (
    35|  text: string,
    36|  caret: number,
    37|): MentionTarget | null => {
    38|  if (caret < 0 || caret > text.length) return null;
    39|  const prefix = text.slice(0, caret);
    40|  const match = prefix.match(MENTION_PATTERN);
    41|  if (!match) return null;
    42|  const query = (match[1] ?? "").toLowerCase();
    43|  const start = caret - query.length - 1;
    44|  return { start, end: caret, query };
    45|};
    46|
    47|function BoardChatComposerImpl({
    48|  placeholder = "Message the board lead. Tag agents with @name.",
    49|  isSending = false,
    50|  disabled = false,
    51|  mentionSuggestions,
    52|  onSend,
    53|}: BoardChatComposerProps) {
    54|  const [value, setValue] = useState("");
    55|  const [mentionTarget, setMentionTarget] = useState<MentionTarget | null>(
    56|    null,
    57|  );
    58|  const [activeMentionIndex, setActiveMentionIndex] = useState(0);
    59|  const textareaRef = useRef<HTMLTextAreaElement | null>(null);
    60|  const closeMenuTimeoutRef = useRef<number | null>(null);
    61|  const shouldFocusAfterSendRef = useRef(false);
    62|
    63|  const mentionOptions = useMemo(() => {
    64|    const handles = new Set<string>(["lead"]);
    65|    (mentionSuggestions ?? []).forEach((candidate) => {
    66|      const handle = normalizeMentionHandle(candidate);
    67|      if (handle) {
    68|        handles.add(handle);
    69|      }
    70|    });
    71|    return [...handles];
    72|  }, [mentionSuggestions]);
    73|
    74|  const filteredMentionOptions = useMemo(() => {
    75|    if (!mentionTarget) return [];
    76|    const query = mentionTarget.query;
    77|    const startsWithMatches = mentionOptions.filter((option) =>
    78|      option.startsWith(query),
    79|    );
    80|    return startsWithMatches.slice(0, MENTION_MAX_OPTIONS);
    81|  }, [mentionOptions, mentionTarget]);
    82|
    83|  const activeIndex =
    84|    filteredMentionOptions.length > 0
    85|      ? Math.min(activeMentionIndex, filteredMentionOptions.length - 1)
    86|      : 0;
    87|
    88|  useEffect(() => {
    89|    if (isSending) return;
    90|    if (!shouldFocusAfterSendRef.current) return;
    91|    shouldFocusAfterSendRef.current = false;
    92|    textareaRef.current?.focus();
    93|  }, [isSending]);
    94|
    95|  useEffect(() => {
    96|    return () => {
    97|      if (closeMenuTimeoutRef.current !== null) {
    98|        window.clearTimeout(closeMenuTimeoutRef.current);
    99|      }
   100|    };
   101|  }, []);
   102|
   103|  const refreshMentionTarget = useCallback(
   104|    (nextValue: string, caret: number) => {
   105|      const nextTarget = findMentionTarget(nextValue, caret);
   106|      setMentionTarget(nextTarget);
   107|    },
   108|    [],
   109|  );
   110|
   111|  const applyMentionSelection = useCallback(
   112|    (handle: string) => {
   113|      const textarea = textareaRef.current;
   114|      if (!textarea || !mentionTarget) return;
   115|      const replacement = `@${handle} `;
   116|      const nextValue =
   117|        value.slice(0, mentionTarget.start) +
   118|        replacement +
   119|        value.slice(mentionTarget.end);
   120|      setValue(nextValue);
   121|      setMentionTarget(null);
   122|      setActiveMentionIndex(0);
   123|      window.requestAnimationFrame(() => {
   124|        const nextCaret = mentionTarget.start + replacement.length;
   125|        textarea.focus();
   126|        textarea.setSelectionRange(nextCaret, nextCaret);
   127|      });
   128|    },
   129|    [mentionTarget, value],
   130|  );
   131|
   132|  const send = useCallback(async () => {
   133|    if (isSending || disabled) return;
   134|    const trimmed = value.trim();
   135|    if (!trimmed) return;
   136|    const ok = await onSend(trimmed);
   137|    shouldFocusAfterSendRef.current = true;
   138|    if (ok) {
   139|      setValue("");
   140|      setMentionTarget(null);
   141|      setActiveMentionIndex(0);
   142|    }
   143|  }, [disabled, isSending, onSend, value]);
   144|
   145|  return (
   146|    <div className="mt-4 space-y-2">
   147|      <div className="relative">
   148|        <Textarea
   149|          ref={textareaRef}
   150|          value={value}
   151|          onChange={(event) => {
   152|            const nextValue = event.target.value;
   153|            setValue(nextValue);
   154|            refreshMentionTarget(
   155|              nextValue,
   156|              event.target.selectionStart ?? nextValue.length,
   157|            );
   158|          }}
   159|          onClick={(event) => {
   160|            refreshMentionTarget(
   161|              value,
   162|              event.currentTarget.selectionStart ?? value.length,
   163|            );
   164|          }}
   165|          onKeyUp={(event) => {
   166|            refreshMentionTarget(
   167|              value,
   168|              event.currentTarget.selectionStart ?? value.length,
   169|            );
   170|          }}
   171|          onBlur={() => {
   172|            if (closeMenuTimeoutRef.current !== null) {
   173|              window.clearTimeout(closeMenuTimeoutRef.current);
   174|            }
   175|            closeMenuTimeoutRef.current = window.setTimeout(() => {
   176|              setMentionTarget(null);
   177|              setActiveMentionIndex(0);
   178|            }, 120);
   179|          }}
   180|          onFocus={(event) => {
   181|            refreshMentionTarget(
   182|              value,
   183|              event.currentTarget.selectionStart ?? value.length,
   184|            );
   185|          }}
   186|          onKeyDown={(event) => {
   187|            if (filteredMentionOptions.length > 0 && mentionTarget) {
   188|              if (event.key === "ArrowDown") {
   189|                event.preventDefault();
   190|                setActiveMentionIndex(
   191|                  (prev) => (prev + 1) % filteredMentionOptions.length,
   192|                );
   193|                return;
   194|              }
   195|              if (event.key === "ArrowUp") {
   196|                event.preventDefault();
   197|                setActiveMentionIndex(
   198|                  (prev) =>
   199|                    (prev - 1 + filteredMentionOptions.length) %
   200|                    filteredMentionOptions.length,
   201|                );
   202|                return;
   203|              }
   204|              if (event.key === "Enter" || event.key === "Tab") {
   205|                event.preventDefault();
   206|                const selected = filteredMentionOptions[activeIndex];
   207|                if (selected) {
   208|                  applyMentionSelection(selected);
   209|                }
   210|                return;
   211|              }
   212|              if (event.key === "Escape") {
   213|                event.preventDefault();
   214|                setMentionTarget(null);
   215|                setActiveMentionIndex(0);
   216|                return;
   217|              }
   218|            }
   219|            if (event.key !== "Enter") return;
   220|            if (event.nativeEvent.isComposing) return;
   221|            if (event.shiftKey) return;
   222|            event.preventDefault();
   223|            void send();
   224|          }}
   225|          placeholder={placeholder}
   226|          className="min-h-[120px]"
   227|          disabled={isSending || disabled}
   228|        />
   229|        {mentionTarget && filteredMentionOptions.length > 0 ? (
   230|          <div className="absolute bottom-full left-0 z-20 mb-2 w-full overflow-hidden rounded-xl border border-slate-200 bg-white shadow-lg">
   231|            <div className="max-h-52 overflow-y-auto py-1">
   232|              {filteredMentionOptions.map((option, index) => (
   233|                <button
   234|                  key={option}
   235|                  type="button"
   236|                  onMouseDown={(event) => {
   237|                    event.preventDefault();
   238|                    applyMentionSelection(option);
   239|                  }}
   240|                  className={`flex w-full items-center justify-between px-3 py-2 text-left text-sm transition ${
   241|                    index === activeIndex
   242|                      ? "bg-slate-100 text-slate-900"
   243|                      : "text-slate-700 hover:bg-slate-50"
   244|                  }`}
   245|                >
   246|                  <span className="font-mono">@{option}</span>
   247|                  <span className="text-xs text-slate-400">mention</span>
   248|                </button>
   249|              ))}
   250|            </div>
   251|          </div>
   252|        ) : null}
   253|      </div>
   254|      <div className="flex justify-end">
   255|        <Button
   256|          onClick={() => void send()}
   257|          disabled={isSending || disabled || !value.trim()}
   258|        >
   259|          {isSending ? "Sending…" : "Send"}
   260|        </Button>
   261|      </div>
   262|    </div>
   263|  );
   264|}
   265|
   266|export const BoardChatComposer = memo(BoardChatComposerImpl);
   267|BoardChatComposer.displayName = "BoardChatComposer";
   268|", "total_lines": 267, "file_size": 8638, "truncated": false, "is_binary": false, "is_image": false}

